const crypto = require('crypto');

function decryptAes256HexCiphertext(hexCiphertext, passphrase) {
  if (typeof hexCiphertext !== 'string' || !hexCiphertext.trim()) throw new Error('hexCiphertext must be a non-empty string');
  if (typeof passphrase !== 'string' || !passphrase) throw new Error('passphrase must be a non-empty string');

  const data = Buffer.from(hexCiphertext, 'hex');
  if (data.length < 16 + 16) throw new Error('Ciphertext too short');

  const salt = data.subarray(0, 16);
  const iv = data.subarray(16, 32);
  const ciphertext = data.subarray(32);

  const key = crypto.pbkdf2Sync(passphrase, salt, 100000, 32, 'sha256');

  const decipher = crypto.createDecipheriv('aes-256-cbc', key, iv);
  const plaintext = Buffer.concat([decipher.update(ciphertext), decipher.final()]).toString('utf8');
  return plaintext;
}

