const tls = require('tls');
const net = require('net');
const { Duplex } = require('stream');

function createSecureTlsStreamPair(options = {}) {
  const {
    serverOptions = {},
    clientOptions = {},
    serverName = 'localhost',
    serverPort = 0,
    ca,
    cert,
    key,
    rejectUnauthorized = false,
    handshakeTimeoutMs = 10000
  } = options;

  const server = tls.createServer({
    ...serverOptions,
    ca,
    cert,
    key,
    rejectUnauthorized,
    requestCert: false,
    ...(!serverOptions.SNI ? {} : {})
  });

  const client = new tls.TLSSocket(new net.Socket(), {
    ...clientOptions,
    ca,
    cert,
    key,
    servername: serverName,
    rejectUnauthorized,
    ALPNProtocols: clientOptions.ALPNProtocols
  });

  let serverSocket;
  let serverClear;
  let clientClear;

  const encryptedDuplex = new Duplex({
    readableObjectMode: false,
    writableObjectMode: false,
    read() {},
    write(chunk, enc, cb) {
      try {
        if (!clientClear) return cb(new Error('Client cleartext stream not ready'));
        clientClear.write(chunk, enc, cb);
      } catch (e) {
        cb(e);
      }
    }
  });

  const cleartextDuplex = new Duplex({
    readableObjectMode: false,
    writableObjectMode: false,
    read() {},
    write(chunk, enc, cb) {
      try {
        if (!serverClear) return cb(new Error('Server cleartext stream not ready'));
        serverClear.write(chunk, enc, cb);
      } catch (e) {
        cb(e);
      }
    }
  });

  const ready = new Promise((resolve, reject) => {
    const timer = setTimeout(() => reject(new Error('TLS handshake timed out')), handshakeTimeoutMs);

    server.on('secureConnection', (tlsSocket) => {
      serverSocket = tlsSocket;

      // Cleartext stream for server side (plaintext in/out)
      serverClear = new Duplex({
        readableObjectMode: false,
        writableObjectMode: false,
        read() {},
        write(chunk, enc, cb) {
          tlsSocket.write(chunk, enc, cb);
        }
      });

      tlsSocket.on('data', (d) => serverClear.push(d));
      tlsSocket.on('end', () => serverClear.push(null));
      tlsSocket.on('close', () => serverClear.destroy());
      tlsSocket.on('error', (e) => serverClear.destroy(e));

      // Encrypted stream: forward raw encrypted bytes between client and server sockets
      // We expose encryptedDuplex as the "wire" stream: writes go to clientClear (which writes to TLS),
      // reads come from serverSocket's underlying encrypted socket.
      const rawServer = tlsSocket._handle && tlsSocket._handle.getPeerCertificate ? null : null;

      // Hook encrypted bytes from server's underlying socket to encryptedDuplex readable
      const underlyingServer = tlsSocket.socket || tlsSocket._parent || tlsSocket._handle;
      // In Node, tlsSocket.socket is the underlying net.Socket
      const netServer = tlsSocket.socket;

      if (netServer && typeof netServer.on === 'function') {
        netServer.on('data', (d) => encryptedDuplex.push(d));
        netServer.on('end', () => encryptedDuplex.push(null));
        netServer.on('close', () => encryptedDuplex.destroy());
        netServer.on('error', (e) => encryptedDuplex.destroy(e));
      }

      // Hook encrypted bytes from client underlying socket to encryptedDuplex writable is handled by clientClear->TLS,
      // but we also need to ensure clientClear exists and is wired.
      // Create client cleartext stream once client is connected.
    });

    server.on('error', (e) => {
      clearTimeout(timer);
      reject(e);
    });

    server.listen(serverPort, () => {
      const port = server.address().port;

      const sock = new net.Socket();
      client.setSocket(sock);

      sock.connect(port, serverName, () => {
        // Client cleartext stream (plaintext in/out)
        clientClear = new Duplex({
          readableObjectMode: false,
          writableObjectMode: false,
          read() {},
          write(chunk, enc, cb) {
            client.write(chunk, enc, cb);
          }
        });

        client.on('data', (d) => clientClear.push(d));
        client.on('end', () => clientClear.push(null));
        client.on('close', () => clientClear.destroy());
        client.on('error', (e) => clientClear.destroy(e));

        // Encrypted stream readable already wired from server side; now wire cleartextDuplex readable from serverClear
        serverClear.on('data', (d) => cleartextDuplex.push(d));
        serverClear.on('end', () => cleartextDuplex.push(null));
        serverClear.on('close', () => cleartextDuplex.destroy());
        serverClear.on('error', (e) => cleartextDuplex.destroy(e));

        // Encrypted stream readable should also be fed from client side if server side isn't available
        sock.on('data', (d) => encryptedDuplex.push(d));
        sock.on('end', () => encryptedDuplex.push(null));
        sock.on('close', () => encryptedDuplex.destroy());
        sock.on('error', (e) => encryptedDuplex.destroy(e));

        client.once('secureConnect', () => {
          clearTimeout(timer);
          resolve({
            encrypted: encryptedDuplex,
            cleartext: cleartextDuplex,
            close: () => {
              try { encryptedDuplex.destroy(); } catch {}
              try { cleartextDuplex.destroy(); } catch {}
              try { client.destroy(); } catch {}
              try { server.close(); } catch {}
              try { if (serverSocket) serverSocket.destroy(); } catch {}
              try { sock.destroy(); } catch {}
            }
          });
        });
      });
    });
  });

  return ready;
}

