function normalizeAbsoluteUrl(inputUrl) {
  const url = new URL(inputUrl, 'http://example.invalid');
  if (!/^[a-zA-Z][a-zA-Z0-9+.-]*:$/.test(url.protocol)) {
    throw new Error('Invalid URL protocol');
