import React from "react";

class PropSyncComponent extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      value: props.value
    };
  }

  componentDidUpdate(prevProps) {
    if (prevProps.value !== this.props.value) {
      this.setState({ value: this.props.value });
    }
  }

  render() {
    return <div>{this.state.value}</div>;
  }
}

export default PropSyncComponent;

import React from "react";

class ScrollTrackingComponent extends React.Component {
  constructor(props) {
    super(props);
    this.state = { value: props.initialValue ?? 0 };
    this._prevScrollY = null;
    this._pendingScrollCapture = false;
  }

  componentDidMount() {
    this._prevScrollY = window.scrollY || window.pageYOffset || 0;
  }

  static getDerivedStateFromProps(nextProps, prevState) {
    if (nextProps.initialValue !== undefined && nextProps.initialValue !== prevState.value) {
      return { value: nextProps.initialValue };
    }
    return null;
  }

  getSnapshotBeforeUpdate() {
    // Capture scroll position immediately before DOM updates
    this._pendingScrollCapture = true;
    return window.scrollY || window.pageYOffset || 0;
  }

  componentDidUpdate(prevProps, prevState, snapshot) {
    if (this._pendingScrollCapture) {
      this._pendingScrollCapture = false;
      const before = snapshot;
      const after = window.scrollY || window.pageYOffset || 0;
      // Do something with before/after if needed
      // console.log("Scroll before:", before, "after:", after);
      this._prevScrollY = before;
    }
  }

  render() {
    return (
      <div style={{ padding: 16 }}>
        <div>Value: {this.state.value}</div>
        <button
          onClick={() => this.setState((s) => ({ value: s.value + 1 }))}
          style={{ marginTop: 8 }}
        >
          Increment
        </button>
      </div>
    );
  }
}

export default ScrollTrackingComponent;

