import React from 'react';

class ScrollPositionRecorder extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      items: Array.from({ length: 20 }, (_, i) => `Item ${i + 1}`),
      scrollPosition: 0,
      lastRecordedPosition: 0,
    };
    this.scrollContainerRef = React.createRef();
  }

  componentDidUpdate(prevProps, prevState) {
    // Record scroll position after update
    if (this.scrollContainerRef.current) {
      const currentPosition = this.scrollContainerRef.current.scrollTop;
      this.setState({ lastRecordedPosition: currentPosition });
      console.log(`Scroll position recorded: ${currentPosition}px`);
    }
  }

  getSnapshotBeforeUpdate(prevProps, prevState) {
    // Capture scroll position immediately before update
    if (this.scrollContainerRef.current) {
      const scrollPosition = this.scrollContainerRef.current.scrollTop;
      this.setState({ scrollPosition });
      console.log(`Scroll position before update: ${scrollPosition}px`);
      return scrollPosition;
    }
    return null;
  }

  handleScroll = (e) => {
    this.setState({ scrollPosition: e.target.scrollTop });
  };

  addMoreItems = () => {
    this.setState((prevState) => ({
      items: [
        ...prevState.items,
        `Item ${prevState.items.length + 1}`,
      ],
    }));
  };

  render() {
    return (
      <div style={{ padding: '20px' }}>
        <h1>Scroll Position Recorder</h1>
        <button onClick={this.addMoreItems}>Add More Items</button>
        <p>Current Scroll: {this.state.scrollPosition}px</p>
        <p>Last Recorded: {this.state.lastRecordedPosition}px</p>
        <div
          ref={this.scrollContainerRef}
          onScroll={this.handleScroll}
          style={{
            height: '300px',
            overflow: 'auto',
            border: '1px solid #ccc',
            marginTop: '20px',
          }}
        >
          {this.state.items.map((item, index) => (
            <div
              key={index}
              style={{
                padding: '10px',
                borderBottom: '1px solid #eee',
                height: '50px',
              }}
            >
              {item}
            </div>
          ))}
        </div>
      </div>
    );
  }
}

export default ScrollPositionRecorder;
